_discord_last_sent = {}   # v3.9.3: per-title cooldown
_DISCORD_COOLDOWN = 60    # seconds between identical alert titles

def send_discord_alert(webhook_url, title, message, color=0xff3030):
    if not webhook_url:
        return
    import time as _t2
    now = _t2.time()
    if now - _discord_last_sent.get(title, 0) < _DISCORD_COOLDOWN:
        return
    _discord_last_sent[title] = now
    payload = {"embeds": [{"title": title, "description": message, "color": color,
        "footer": {"text": "RavenMiner HQ " + VERSION + " • " + _t2.strftime("%H:%M:%S")}}]}
    def _post():
        try: requests.post(webhook_url, json=payload, timeout=6)
        except Exception as ex: print("Discord webhook error:", ex)
    import threading as _th
    _th.Thread(target=_post, daemon=True).start()

