        self.max_bars=200;self.found_blocks=-1;self.last_shares=0
        self._alerted_temp    = False
        self._alerted_vr_temp = False
        self._alerted_hash    = False
        self._alerted_offline = False
        self._offline_count   = 0
        self._last_rej        = 0
        self.glow_step=80;self.glow_dir=1;self.block_start=time.time()
        self._is_online=False; self._live_alpha=0; self._live_dir=1  # v3.9.3
        self._gold_pulse_id=None  # v3.9.3
