        self._stat_block(p,"FREQUENCY","--","MHz",CYAN,"lbl_freq",COL_R); self._divider(p)
        self._stat_block(p,"CORE VOLT","--","mV",PURPLE_GLOW,"lbl_vcore",COL_R); self._divider(p)
        self._stat_block(p,"FAN SPEED","--","%",WHITE,"lbl_fan",COL_R); self._divider(p)
        self._stat_block(p,"FAN RPM","--","rpm",DIM,"lbl_fanrpm",COL_R); self._divider(p)
        tk.Frame(p,height=2,bg=GOLD).pack(fill="x",pady=8)
        tk.Label(p,text="\u16a0  BTC PRICE  \u16a0",font=("Segoe UI",14),fg=GOLD,bg=COL_R).pack()
        self.lbl_btc=tk.Label(p,text="--",font=("Courier",28,"bold"),fg=GOLD_BRIGHT,bg=COL_R); self.lbl_btc.pack(pady=4)
        self._divider(p)
        self._stat_block(p,"WiFi RSSI","--","dBm",CYAN,"lbl_wifi",COL_R); self._divider(p)
        # v3.9.3: hi-res gear image with golden glow ring on hover
        _GEAR_SIZE = 80
        gear_cv = tk.Canvas(p, width=_GEAR_SIZE, height=_GEAR_SIZE,
                            bg=COL_R, highlightthickness=0)  # bg matches panel
        gear_cv.pack(pady=6)
        gear_cv._photo_normal = None
        gear_cv._photo_hover  = None

        def _remove_white_bg(img, threshold=240, feather=15):
            """v3.9.3: Remove white/near-white background and feather edges."""
            img = img.convert("RGBA")
            data = img.load()
            w2, h2 = img.size
            for y in range(h2):
                for x in range(w2):
                    r2,g2,b2,a2 = data[x,y]
                    # how "white" is this pixel
                    whiteness = min(r2,g2,b2)
                    if whiteness >= threshold:
                        # fully transparent
                        data[x,y] = (r2,g2,b2,0)
                    elif whiteness >= threshold - feather:
                        # feathered semi-transparent edge
                        alpha = int((threshold - whiteness) / feather * 255)
                        data[x,y] = (r2,g2,b2,alpha)
            return img

        def _load_gear_images():
            if not PIL_OK:
                return None, None
            try:
                raw = base64.b64decode(GEAR_IMG_B64)
                img = Image.open(io.BytesIO(raw)).convert("RGBA")
                img = _remove_white_bg(img, threshold=240, feather=20)
                img = img.resize((_GEAR_SIZE, _GEAR_SIZE), Image.LANCZOS)
                # normal — slight dim
                normal = img.copy()
                r2,g2,b2,a2 = normal.split()
                r2 = r2.point(lambda p: int(p*0.85))
                g2 = g2.point(lambda p: int(p*0.85))
                b2 = b2.point(lambda p: int(p*0.85))
                normal = Image.merge("RGBA",(r2,g2,b2,a2))
                return ImageTk.PhotoImage(normal), ImageTk.PhotoImage(img)
            except Exception as ex:
                print("Gear image load error:", ex)
                return None, None

        _pn, _ph = _load_gear_images()
        gear_cv._photo_normal = _pn
        gear_cv._photo_hover  = _ph

        # v3.9.3: shimmer state
        gear_cv._shimmer_phase = 0
        gear_cv._shimmer_id    = None

        def _render_gear(hover=False, shimmer_phase=0):
            gear_cv.delete("all")
            photo = gear_cv._photo_hover if hover else gear_cv._photo_normal
            cx = _GEAR_SIZE // 2
            if photo:
                gear_cv.create_image(cx, cx, image=photo, anchor="center")
            else:
                r_out = 28
                fill_col = GOLD_BRIGHT if hover else "#9d5fff"
                pts = []
                for i in range(20):
                    angle = math.radians(i*(360/20))
                    r = r_out if i%2==0 else r_out-8
                    pts += [cx+r*math.cos(angle), cx+r*math.sin(angle)]
                gear_cv.create_polygon(pts, fill=fill_col, outline=GOLD, width=1)
            # shimmer arc sweeps around the gear
            arc_start = (shimmer_phase * 12) % 360
            for i, (arc_w, opacity) in enumerate([(8, 0.25),(5, 0.45),(2, 0.75)]):
                offset = i * 18
                intensity = int(180 + opacity * 75)
                shimmer_col = f"#{intensity:02x}{int(intensity*0.82):02x}{0x22:02x}"
                gear_cv.create_arc(3, 3, _GEAR_SIZE-3, _GEAR_SIZE-3,
                                   start=(arc_start + offset) % 360, extent=55,
                                   style="arc", outline=shimmer_col, width=arc_w)
            if hover:
                pad = 4
                for width, col in [(10,"#c9a84c"),(6,"#f0c040"),(3,"#ffe87a")]:
                    gear_cv.create_oval(pad, pad, _GEAR_SIZE-pad, _GEAR_SIZE-pad,
                                        outline=col, width=width, fill="")

        def _shimmer_loop():
            try:
                if not gear_cv.winfo_exists(): return
            except Exception: return
            gear_cv._shimmer_phase = (gear_cv._shimmer_phase + 1) % 30
            _render_gear(hover=False, shimmer_phase=gear_cv._shimmer_phase)
            gear_cv._shimmer_id = gear_cv.after(80, _shimmer_loop)

        _render_gear(hover=False)
        gear_cv._shimmer_id = gear_cv.after(80, _shimmer_loop)

        def _gear_enter(e):
            if gear_cv._shimmer_id:
                try: gear_cv.after_cancel(gear_cv._shimmer_id)
                except Exception: pass
                gear_cv._shimmer_id = None
            _render_gear(hover=True, shimmer_phase=gear_cv._shimmer_phase)
            rune_lbl.config(fg=GOLD_BRIGHT, font=("Segoe UI", 18, "bold"))

        def _gear_leave(e):
            rune_lbl.config(fg=PURPLE_DIM, font=("Segoe UI", 18))
            gear_cv._shimmer_id = gear_cv.after(80, _shimmer_loop)

        gear_cv.bind("<Enter>",    _gear_enter)
        gear_cv.bind("<Leave>",    _gear_leave)
        gear_cv.bind("<Button-1>", lambda e: SettingsWindow(self.root, MINER_IP))
        gear_cv.config(cursor="hand2")

        rune_lbl = tk.Label(p, text="\u16a0  \u16b1  \u16d6  \u16b3  \u16a8",
                            font=("Segoe UI", 18), fg=PURPLE_DIM, bg=COL_R)
        rune_lbl.pack(pady=8)
        rune_lbl.bind("<Enter>",    _gear_enter)
        rune_lbl.bind("<Leave>",    _gear_leave)
        rune_lbl.config(cursor="hand2")
        rune_lbl.bind("<Button-1>", lambda e: SettingsWindow(self.root, MINER_IP))

