    def _draw_gauge(self,canvas,temp,needle_color=None,warn=55,crit=60,lo=0.0,hi=120.0,voltage_mode=False,watt_mode=False,curr_mode=False):
        if needle_color is None: needle_color=ORANGE
        c=canvas; c.delete("all"); cx,cy,r=100,92,54
        MAX_TEMP=hi; MIN_TEMP=lo
        span=max(MAX_TEMP-MIN_TEMP,0.001)
        def _ang(v): return math.radians(210-((v-MIN_TEMP)/span)*240)

        if voltage_mode:
            # ── Coloured arc bands: red 0-11.5, orange 11.5-11.9, green 11.9-12.9, orange 12.9+ ──
            bands=[
                (lo,    11.5, RED),
                (11.5,  11.9, ORANGE),
                (11.9,  12.9, GREEN),
                (12.9,  hi,   ORANGE),
            ]
            for b_lo, b_hi, bcol in bands:
                b_lo=max(b_lo,lo); b_hi=min(b_hi,hi)
                if b_lo>=b_hi: continue
                a_start=math.degrees(_ang(b_lo))
                a_end  =math.degrees(_ang(b_hi))
                extent = a_end-a_start
                c.create_arc(cx-r,cy-r,cx+r,cy+r,start=a_start,extent=extent,
                             style="arc",outline=bcol,width=16)
            # tick marks on OUTER perimeter: major 1V, minor 0.5V, micro 0.1V
            v = lo
            while v <= hi + 0.001:
                vr = round(v, 1)
                is_major = abs(vr - round(vr)) < 0.01          # whole volt
                is_half  = abs((vr * 2) - round(vr * 2)) < 0.01 and not is_major  # 0.5V
                is_micro = not is_major and not is_half         # 0.1V
                t_far  = r + 16                                  # outer rim
                t_near = r + (5 if is_major else 10 if is_half else 13)  # tick depth
                col    = "#ddddff" if is_major else "#7777aa" if is_half else "#333355"
                lw     = 2 if is_major else 1
                a = _ang(vr)
                c.create_line(cx+t_far *math.cos(a), cy-t_far *math.sin(a),
                              cx+t_near*math.cos(a), cy-t_near*math.sin(a), fill=col, width=lw)
                v = round(v + 0.1, 1)
            # labels every 0.5V on outer perimeter
            v = lo
            while v <= hi + 0.001:
                vr = round(v, 1)
                is_whole = abs(vr - round(vr)) < 0.01
                a   = _ang(vr)
                lx  = cx + (r + 26) * math.cos(a)
                ly  = cy - (r + 26) * math.sin(a)
                lbl_col = RED if vr < 11.5 else ORANGE if vr < 11.9 else GREEN if vr <= 12.9 else ORANGE
                txt  = str(int(vr)) if is_whole else str(vr)
                font = ("Courier", 7, "bold") if is_whole else ("Courier", 6)
                c.create_text(lx, ly, text=txt, fill=lbl_col, font=font)
                v = round(v + 0.5, 1)
            # needle
            pct=min(max((temp-MIN_TEMP)/span,0),1)
            color=RED if temp<11.5 else ORANGE if temp<11.9 else GREEN if temp<=12.9 else ORANGE
            ar=math.radians(210-240*pct)
            c.create_line(cx,cy,cx+(r-10)*math.cos(ar),cy-(r-10)*math.sin(ar),fill=GOLD_BRIGHT,width=3)
            c.create_oval(cx-5,cy-5,cx+5,cy+5,fill=GOLD,outline="")
            c.create_text(cx,cy+18,text=str(round(temp,2))+" V",font=("Courier",13,"bold"),fill=color)
        elif curr_mode:
            # ── Current gauge: green→orange→red bands, fractional outer ticks ──
            bands=[
                (0,    8.0,  GREEN),
                (8.0,  10.0, ORANGE),
                (10.0, 12.0, RED),
                (12.0, hi,   "#ff2200"),
            ]
            for b_lo, b_hi, bcol in bands:
                b_lo=max(b_lo,lo); b_hi=min(b_hi,hi)
                if b_lo>=b_hi: continue
                a_start=math.degrees(_ang(b_lo))
                a_end  =math.degrees(_ang(b_hi))
                c.create_arc(cx-r,cy-r,cx+r,cy+r,start=a_start,extent=a_end-a_start,
                             style="arc",outline=bcol,width=16)
            # outer ticks: major 1A, minor 0.5A, micro 0.2A (streamlined)
            v=lo
            while v<=hi+0.001:
                vr=round(v,1)
                is_major=abs(vr-round(vr))<0.01
                is_half =abs((vr*2)-round(vr*2))<0.01 and not is_major
                t_far =r+16
                t_near=r+(5 if is_major else 10 if is_half else 13)
                col   ="#ddddff" if is_major else "#7777aa" if is_half else "#333355"
                lw    =2 if is_major else 1
                a=_ang(vr)
                c.create_line(cx+t_far*math.cos(a),cy-t_far*math.sin(a),
                              cx+t_near*math.cos(a),cy-t_near*math.sin(a),fill=col,width=lw)
                v=round(v+0.2,1)
            # labels every 1A only
            v=lo
            while v<=hi+0.001:
                vr=round(v,1)
                a=_ang(vr)
                lx=cx+(r+26)*math.cos(a); ly=cy-(r+26)*math.sin(a)
                lbl_col=GREEN if vr<8 else ORANGE if vr<10 else RED
                c.create_text(lx,ly,text=str(int(vr)),fill=lbl_col,font=("Courier",7,"bold"))
                v=round(v+1.0,1)
            # needle
            pct=min(max((temp-lo)/span,0),1)
            color=GREEN if temp<8 else ORANGE if temp<10 else RED
            ar=math.radians(210-240*pct)
            c.create_line(cx,cy,cx+(r-10)*math.cos(ar),cy-(r-10)*math.sin(ar),fill=GOLD_BRIGHT,width=3)
            c.create_oval(cx-5,cy-5,cx+5,cy+5,fill=GOLD,outline="")
            c.create_text(cx,cy+18,text=str(round(temp,2))+" A",font=("Courier",13,"bold"),fill=color)
        else:
            # ── Standard temp gauge ──
            for t in range(0, int(MAX_TEMP)+1, 5):
                a=math.radians(210-(t/MAX_TEMP)*240)
                is_major=(t%20==0)
                t_out=r+2; t_in=r+(10 if is_major else 5)
                col="#666688" if is_major else "#333355"
                lw=2 if is_major else 1
                c.create_line(cx+t_out*math.cos(a),cy-t_out*math.sin(a),
                              cx+t_in*math.cos(a), cy-t_in*math.sin(a),fill=col,width=lw)
            for t in range(0, int(MAX_TEMP)+1, 10):
                a=math.radians(210-(t/MAX_TEMP)*240)
                lx=cx+(r+22)*math.cos(a); ly=cy-(r+22)*math.sin(a)
                lbl_col=RED if t>=crit else ORANGE if t>=warn else GREEN
                c.create_text(lx,ly,text=str(t),fill=lbl_col,font=("Courier",7,"bold"))
            c.create_arc(cx-r,cy-r,cx+r,cy+r,start=210,extent=-240,style="arc",outline=PURPLE_DIM,width=16)
            pct=min(max((temp-MIN_TEMP)/span,0),1); sweep=-240*pct
            color=GREEN if temp<warn else ORANGE if temp<=crit else RED
            if abs(sweep)>0.5: c.create_arc(cx-r,cy-r,cx+r,cy+r,start=210,extent=sweep,style="arc",outline=color,width=16)
            ar=math.radians(210-240*pct)
            c.create_line(cx,cy,cx+(r-10)*math.cos(ar),cy-(r-10)*math.sin(ar),fill=GOLD_BRIGHT,width=3)
            c.create_oval(cx-5,cy-5,cx+5,cy+5,fill=GOLD,outline="")
            c.create_text(cx,cy+18,text=str(round(temp,1))+" C",font=("Courier",14,"bold"),fill=color)

    def _draw_bars(self, c=None, _anim_phase=0):
        try:
            if c is None:
                c = self.bar_canvas
            c.update_idletasks()
            w = c.winfo_width()
            h = c.winfo_height()
            c.delete("all")
            if h < 10:
                h = 220
            if not self.hr_history:
                return
        except Exception:
            return
        # v3.9.3: collect line points for smooth curve
        _line_pts   = []   # (x_mid, y, color) per sub-bar
        # _drop_pts removed — perf fix

        import math

        max_points = 40
        points = list(self.hr_history)[-max_points:]
        n = len(points)
        if n == 0:
            return

        mx = max(points) or 1
        mn = min(points) or 0

        # v3.9.3: anchor floor/ceiling to show all colour bands
        data_range = max(mx - mn, 0.05)
        if data_range < 0.1:  # no real variance — use safe defaults
            floor   = max(0.0, mn - 0.5)
            ceiling = mx + 0.5
        else:  # real data — tight range for maximum waveform swing
            floor   = mn - data_range * 0.05
            ceiling = mx + data_range * 0.05

        sub_w   = max(1.0, (w - 72) / max(1, n * 16))  # float: fills full width
        seg_h   = 5
        seg_gap = 2
        seg_unit = seg_h + seg_gap

        HR_LOW_THRESHOLD = 6.4

        # ── Animated pulse: a bright shimmer wave sweeps left→right ──
        wave_speed = 8          # sub-bars per animation phase step
        wave_width = 30         # width of the shimmer in sub-bars
        wave_pos   = (_anim_phase * wave_speed) % (n * 16 + wave_width)

        def _hr_band(v):
            if v >= 6.5:   return "gold"
            elif v >= 6.4: return "green"
            elif v >= 6.3: return "violet"
            elif v >= 6.0: return "blue"
            else:          return "red"

        BAND_COLOURS = {
            "gold"  : (255, 231, 45),
            "green" : (50,  221, 57),
            "violet": (211, 50,  231),
            "blue"  : (40,  175, 255),
            "red"   : (231, 10,  0),
        }

        def _brighten(r, g, b, amt):
            """Boost RGB toward white by amt (0.0–1.0)."""
            return (
                int(min(255, r + (255 - r) * amt)),
                int(min(255, g + (255 - g) * amt)),
                int(min(255, b + (255 - b) * amt)),
            )

        def norm_val(v, idx=0):
            base   = max(0.0, min(1.0, (v - floor) / max(ceiling - floor, 0.001)))
            curved = base ** 0.75  # v3.9.3: more linear — emphasises differences
            jitter = math.sin(idx * 2.399) * 0.12  # v3.9.3: 3× bigger wave ripple
            return max(0.0, min(1.0, curved + jitter))

        max_segs = max(1, h // seg_unit)
        usable_h = max_segs * seg_unit

        # ── scale margins for left/right Y-axis labels ──
        scale_w = 36  # px reserved each side for labels

        # ── faint horizontal grid lines + left/right HR scale ──
        n_grid = 5
        for gi in range(n_grid + 1):
            frac  = gi / n_grid
            hr_val = floor + frac * (ceiling - floor)
            gy    = int(h - 2 - frac * (h - 4))
            # faint grid line
            c.create_line(scale_w, gy, w - scale_w, gy,
                          fill="#1a1a2e", width=1, dash=(2, 6))
            lbl = f"{hr_val:.2f}"
            # left label
            c.create_text(scale_w - 2, gy, text=lbl, anchor="e",
                          fill="#7878aa", font=("Courier", 7))
            # right label
            c.create_text(w - scale_w + 2, gy, text=lbl, anchor="w",
                          fill="#7878aa", font=("Courier", 7))

        for i, val in enumerate(points):
            cur_norm = norm_val(val, i)
            next_val = points[i + 1] if i + 1 < n else val
            nxt_norm = norm_val(next_val, i + 1)

            def _hr_band_v(v):
                if v >= 6.5:   return "gold"
                elif v >= 6.4: return "green"
                elif v >= 6.3: return "violet"
                elif v >= 6.0: return "blue"
                else:          return "red"

            hr_band      = _hr_band_v(val)
            next_hr_band = _hr_band_v(next_val)

            for sub in range(16):
                t      = sub / 16.0
                ease   = t * t * (3 - 2 * t)
                interp_norm = cur_norm + (nxt_norm - cur_norm) * ease
                _si = i * 16 + sub
                x0  = int(scale_w + _si * sub_w)
                x1  = max(x0 + 1, int(scale_w + (_si + 1) * sub_w))
                n_segs = max(1, int(interp_norm * max_segs))

                bar_band = hr_band if t < 0.5 else next_hr_band
                br, bg_int, bb = (int(x) for x in BAND_COLOURS[bar_band])

                # ── shimmer wave: how much to brighten this sub-bar ──
                sub_idx = i * 16 + sub
                dist = abs(sub_idx - wave_pos)
                if dist < wave_width:
                    shimmer = (1.0 - dist / wave_width) * 0.75  # v3.9.3: stronger shimmer
                    br, bg_int, bb = _brighten(br, bg_int, bb, shimmer)
                br = int(br); bg_int = int(bg_int); bb = int(bb)  # safe — avoids global BG collision

                bar_color = f"#{br:02x}{bg_int:02x}{bb:02x}"

                # draw bar — very dim body, bright top line drawn later
                if n_segs > 0:
                    bar_top = h - 2 - n_segs * seg_unit
                    if bar_top < h - 2:
                        c.create_rectangle(x0, bar_top, x1, h - 2,
                            fill=f"#{int(br*0.128):02x}{int(bg_int*0.128):02x}{int(bb*0.128):02x}", outline="")
                # collect top-line point for smooth curve
                line_y = h - 2 - n_segs * seg_unit  # v3.9.3: line at very top of bar
                tr, tg, tb = (int(x) for x in _brighten(br, bg_int, bb, 0.45))
                x_mid = x0 + (x1 - x0) // 2
                _line_pts.append((x_mid, line_y, f"#{tr:02x}{tg:02x}{tb:02x}"))

        # ── Schedule next animation frame ──
        # v3.9.3: draw smooth curved line connecting all data points
        if len(_line_pts) >= 2:
            # drop lines removed — v3.9.3 perf fix
            # draw smooth line — collect all x,y coords then one polyline per colour band
            pts_flat = []
            for xm, ly, col in _line_pts:
                pts_flat += [xm, ly]
            if len(pts_flat) >= 4:
                c.create_line(pts_flat, fill=_line_pts[len(_line_pts)//2][2],
                              width=2, smooth=True, capstyle="round", joinstyle="round")
                # glow pass — slightly wider, semi-transparent feel
                c.create_line(pts_flat, fill=_line_pts[len(_line_pts)//2][2],
                              width=3, smooth=True, capstyle="round", joinstyle="round")
            # bright dot at each actual data point
            for xm, ly, col in _line_pts[::16]:  # every 16 subs = 1 data point
                c.create_oval(xm-2, ly-2, xm+2, ly+2, fill=col, outline="")

        # v3.9.3: self-scheduling animation — guarded against KeyboardInterrupt
        if hasattr(self, "bar_canvas"):
            try:
                if not self.bar_canvas.winfo_exists():
                    return
            except Exception:
                return
            if _anim_phase == 0 and hasattr(self, "_bar_anim_id") and self._bar_anim_id:
                try: self.root.after_cancel(self._bar_anim_id)
                except Exception: pass
            def _next_frame(ph=_anim_phase + 1):
                try:
                    self._draw_bars(self.bar_canvas, ph)
                except (KeyboardInterrupt, SystemExit):
                    raise
                except Exception as _e:
                    print(f"Graph anim error: {_e}")
            self._bar_anim_id = self.root.after(80, _next_frame)  # v3.9.3: 80ms perf


    def _draw_countdown_bar(self,elapsed,total):
        c=self.cdown_canvas; c.update_idletasks(); w=c.winfo_width(); c.delete("all")
        pct=min(elapsed/total,1.0); filled=int(pct*(w-20))
        c.create_rectangle(10,14,w-10,28,outline=PURPLE_DIM,fill="#0a0018")
        color=GREEN if pct<0.6 else GOLD if pct<0.85 else RED
        if filled>0: c.create_rectangle(10,14,10+filled,28,fill=color,outline="")
        if 0<filled<w-20: c.create_oval(8+filled,10,14+filled,30,fill=color,outline="")

    def _countdown_loop(self):
        elapsed=time.time()-self.block_start; remaining=max(0,BITCOIN_BLOCK_TIME-(elapsed%BITCOIN_BLOCK_TIME))
        m=int(remaining//60); s=int(remaining%60)
        self.lbl_countdown.config(text="~"+str(m)+"m "+str(s).zfill(2)+"s",fg=GOLD_BRIGHT if remaining>120 else RED)
        self._draw_countdown_bar(elapsed%BITCOIN_BLOCK_TIME,BITCOIN_BLOCK_TIME)
        self.root.after(1000,self._countdown_loop)

    def _glow_loop(self):
        self.glow_step+=self.glow_dir*22  # v3.9.3: faster pulse step
        if self.glow_step>=255: self.glow_step=255; self.glow_dir=-1
        elif self.glow_step<=20: self.glow_step=20; self.glow_dir=1
        v=self.glow_step
        # v3.9.3: electric blue — near-black dim to blazing cyan-white peak
        try: self.lbl_hashrate.config(fg="#{:02x}{:02x}{:02x}".format(
            int(v*0.35),
            int(v*0.70),
            255))
        except Exception: pass
        self.root.after(55,self._glow_loop)  # v3.9.3: perf

    def _trigger_block_flash(self):
        self.flash_frame.place(relx=0,rely=0,relwidth=1,relheight=1)
        self.block_start=time.time(); self.root.after(4000,lambda: self.flash_frame.place_forget())
        try:
            import winsound
            for _ in range(5): winsound.MessageBeep(winsound.MB_ICONEXCLAMATION)
            self.root.after(500, lambda: [winsound.Beep(880,400) for _ in range(6)])
        except Exception:
            try:
                import subprocess, sys
                if sys.platform=="darwin": subprocess.Popen(["afplay","/System/Library/Sounds/Glass.aiff"])
                else: subprocess.Popen(["paplay","/usr/share/sounds/freedesktop/stereo/complete.oga"])
            except Exception: self.root.bell()

    def _tick_clock(self):
        self.lbl_clock.config(text=time.strftime("%H:%M:%S")); self.root.after(1000,self._tick_clock)

    def _setup_tray(self):
        if not TRAY_OK: return
        try:
            icon_img=make_tray_icon()
            menu=(item("Show RavenMiner HQ",self._show_window,default=True),item("Quit",self._quit_app))
            self.tray_icon=pystray.Icon("ravenminer",icon_img,"RavenMiner HQ",menu)
            threading.Thread(target=self.tray_icon.run,daemon=True).start()
        except Exception as e: print("Tray error:",e)

    def _on_close(self):
        self.root.withdraw()
        if self.tray_icon:
            try: self.tray_icon.notify("RavenMiner HQ is still running","Click to restore")
            except Exception: pass

    def _on_minimize(self,event=None):
        if self.root.state()=="iconic":
            self.root.withdraw()

    def _show_window(self):
        self.root.after(0,self.root.deiconify)
        self.root.after(0,lambda: self.root.state("zoomed"))

    def _quit_app(self):
        if self.tray_icon: self.tray_icon.stop()
        self.root.after(0,self.root.quit)



    def _runes_pulse(self):
        """Continuously pulse the runic title between gold and bright gold-white."""
        import math
        self._runes_pulse_phase = getattr(self, "_runes_pulse_phase", 0.0) + 0.045
        t = (math.sin(self._runes_pulse_phase) + 1) / 2   # 0.0 -> 1.0
        # interpolate #f0c040 (GOLD_BRIGHT) <-> #ffe87a (bright gold-white)
        r = int(0xf0 + t * (0xff - 0xf0))
        g = int(0xc0 + t * (0xe8 - 0xc0))
        b = int(0x40 + t * (0x7a - 0x40))
        color = f"#{r:02x}{g:02x}{b:02x}"
        try:
            self.lbl_runes.config(fg=color)
        except Exception:
            return
        self.root.after(55, self._runes_pulse)

    def _start_live_pulse(self):
        self._is_online = True

    def _stop_live_pulse(self):
        self._is_online = False

    def _live_tick(self):
        """Always-running tick — reacts to self._is_online, never stops."""
        online = getattr(self, "_is_online", False)
        if online:
            self._live_alpha = getattr(self, "_live_alpha", 0) + getattr(self, "_live_dir", 1) * 14
            if self._live_alpha >= 255: self._live_alpha = 255; self._live_dir = -1
            elif self._live_alpha <= 60: self._live_alpha = 60;  self._live_dir  =  1
            g     = min(255, 200 + int(self._live_alpha * 0.22))
            color = f"#{0:02x}{g:02x}{0:02x}"
            try: self.lbl_live.config(text="◉  LIVE", fg=color, font=("Courier",16,"bold"))
            except Exception: pass
        else:
            self._live_alpha = 0
            try: self.lbl_live.config(text="◉  OFFLINE", fg="#ff2222", font=("Courier",16,"bold"))
            except Exception: pass
        self.root.after(55, self._live_tick)

    def _start_gold_pulse(self):
        """Pulse POOL and UPTIME labels in gold while connected."""
        if getattr(self, "_gold_connected", False):
            return  # chain already running — prevents runaway accumulation
        self._gold_connected = True
        self._gold_alpha     = 0
        self._gold_dir       = 1
        self._gold_tick()

    def _stop_gold_pulse(self):
        self._gold_connected = False
        if self._gold_pulse_id:
            try: self.root.after_cancel(self._gold_pulse_id)
            except Exception: pass
            self._gold_pulse_id = None
        try:
            self.lbl_pool.config(fg=GOLD)
            self.lbl_uptime.config(fg=GOLD)
        except Exception: pass

    def _gold_tick(self):
        if not getattr(self, "_gold_connected", False):
            return
        self._gold_alpha += self._gold_dir * 8
        if self._gold_alpha >= 255:
            self._gold_alpha = 255; self._gold_dir = -1
        elif self._gold_alpha <= 60:
            self._gold_alpha = 60;  self._gold_dir  = 1
        a = self._gold_alpha
        r = int(0xc9 + (0xf0 - 0xc9) * a / 255)
        g = int(0xa8 + (0xc0 - 0xa8) * a / 255)
        b = int(0x4c + (0x40 - 0x4c) * a / 255)
        color = f"#{r:02x}{g:02x}{b:02x}"
        try:
            self.lbl_pool.config(fg=color)
            self.lbl_uptime.config(fg=color)
        except Exception: return
        self._gold_pulse_id = self.root.after(70, self._gold_tick)

    def fetch_miner(self):
        _url = API_URL   # snapshot globals at call start — avoids mid-call race
        _ip  = MINER_IP
        try:
            r=requests.get(_url,timeout=6)
            if r.status_code==200:
                with self._data_lock:
                    self.data=r.json()
                self.root.after(0, self._start_live_pulse)
                self.root.after(0, self._start_gold_pulse)
                self._offline_count   = 0
                self._alerted_offline = False
                return True
        except Exception as e:
            err=str(e)[:60]
            self.root.after(0,lambda: self.lbl_status.config(text="Error: "+err,fg=RED))
        self.root.after(0, self._stop_live_pulse)
        self.root.after(0, self._stop_gold_pulse)
        self._offline_count += 1
        if self._offline_count >= 3 and not self._alerted_offline:
            acfg = load_alert_config()
            if acfg.get("alert_on_offline", True):
                send_discord_alert(acfg.get("discord_webhook",""),
                    "🔴  MINER OFFLINE",
                    "RavenMiner HQ lost contact with **"+_ip+"**\n3 consecutive failed polls.",
                    color=0xff2222)
            self._alerted_offline = True
        return False

    def fetch_btc(self):
        try:
            r=requests.get("https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd",timeout=6)
            with self._btc_lock:
                self.btc=r.json()["bitcoin"]["usd"]
        except Exception: pass

    def refresh_loop(self):
        self.fetch_btc()  # initial fetch on startup
        while True:
            try:  # v3.9.3: guard — unhandled exception must not silently kill polling
                ok=self.fetch_miner()
                self._btc_counter+=1
                if self._btc_counter >= max(1, int(60/max(REFRESH,0.1))):
                    self.fetch_btc()
                    self._btc_counter=0
                if ok and not getattr(self, '_update_pending', False):
                    self._update_pending = True
                    self.root.after(50, self._dispatch_update)  # v3.9.3: breathing room
            except Exception as _loop_ex:
                print(f"refresh_loop error (non-fatal): {_loop_ex}")
            time.sleep(max(REFRESH, 0.1))

    def start_refresh(self): threading.Thread(target=self.refresh_loop,daemon=True).start()

    def _dispatch_update(self):
        self._update_pending = False
        self.update_display()

    def update_display(self):
        global _alert_cfg_global_cache  # v3.9.3
        with self._data_lock:
            d=dict(self.data)
        new_blocks=d.get("foundBlocks",0)
        old_blocks=self.found_blocks
        if new_blocks>old_blocks and old_blocks>=0: self.root.after(0,self._trigger_block_flash)
        self.found_blocks=new_blocks
        new_shares=d.get("sharesAccepted",0)
        if new_shares>self.last_shares: self.root.after(0,self._trigger_valknut_flash)
        self.last_shares=new_shares
        temp=(d.get("temp") or 0)
        self._draw_gauge(self.gauge_canvas, temp, ORANGE, warn=55, crit=70)
        # lbl_asic_temp removed — data now fed to ASIC gauge
        vr_temp=(d.get("vrTemp") or 0)
        self._draw_gauge(self.vr_gauge_canvas, vr_temp, CYAN, warn=50, crit=65)
        # lbl_vr_temp removed — data now fed to VR gauge
        self._draw_gauge(self.gauge_canvas, temp, ORANGE, warn=55, crit=70)
        self._draw_gauge(self.vr_gauge_canvas, (d.get("vrTemp") or 0), CYAN, warn=50, crit=65)
        hr=(d.get("hashRate") or 0)/1000; hr1m=(d.get("hashRate_1m") or 0)/1000
        hr10=(d.get("hashRate_10m") or 0)/1000; hr1h=(d.get("hashRate_1h") or 0)/1000
        self.lbl_hashrate.config(text=f"{hr:.3f}")
        self.lbl_hr1m.config(text=str(round(hr1m,3))+" TH/s")
        self.lbl_hr10m.config(text=str(round(hr10,3))+" TH/s")
        self.lbl_hr1h.config(text=str(round(hr1h,3))+" TH/s")
        self.hr_history.append(hr)
        self._last_data_time = time.time()
        if not hasattr(self, "_last_hr_draw") or time.time() - self._last_hr_draw >= HR_REFRESH:
            # kick-start graph animation if not already running
            if not getattr(self, "_bar_anim_id", None):
                self._draw_bars()
            self._last_hr_draw = time.time()
        acc=d.get("sharesAccepted",0); rej=d.get("sharesRejected",0)
        self.lbl_acc.config(text=str(acc))
        self.lbl_rej.config(text=str(rej),fg=RED if rej>0 else GREEN)
        _total=acc+rej; _pct=round(rej/_total*100,2) if _total>0 else 0.0
        self.lbl_rej_pct.config(text=f"{_pct:.2f} %",fg=RED if _pct>=1.0 else ORANGE if _pct>0 else GREEN)
        self.lbl_bestdiff.config(text=fmt_diff(d.get("bestSessionDiff",0)))
        self.lbl_pool.config(text=d.get("stratumURL","--"))
        self.lbl_uptime.config(text=fmt_uptime((d.get("uptimeSeconds") or 0)))
        pwr=(d.get("power") or 0)
        # v3.9.3: green 0-120W, orange 120-130W, red 130W+
        self.lbl_power.config(text=str(round(pwr,1))+" W",fg=RED if pwr>=130 else ORANGE if pwr>=120 else GREEN)
        # v3.9.3: green 0-10A, orange 10-12A, red 12A+
        _cur=round((d.get("currentA") or 0),2)
        self.lbl_current.config(text=str(_cur)+" A",fg=RED if _cur>=12 else ORANGE if _cur>=10 else GREEN)
        self._draw_gauge(self.curr_gauge_canvas, _cur, ORANGE, warn=10.0, crit=12.0, lo=0.0, hi=15.0, curr_mode=True)
        # v3.9.3: red <12V, orange 11.99-12V, green 12-12.8V, orange 12.8-13.1V, red 13.1V+
        _vlt=round((d.get("voltage") or 0)/1000,2)
        _vlt_fg=(RED if _vlt<11.99 else ORANGE if _vlt<12.0 else GREEN if _vlt<12.8 else ORANGE if _vlt<13.1 else RED)
        self.lbl_voltage.config(text=str(_vlt)+" V",fg=_vlt_fg)
        self._draw_gauge(self.volt_gauge_canvas, _vlt, GREEN, warn=11.9, crit=11.5, lo=10.0, hi=13.5, voltage_mode=True)
        self.lbl_freq.config(text=str(d.get("frequency","--"))+" MHz")
        self.lbl_vcore.config(text=str(d.get("coreVoltageActual","--"))+" mV")
        fan=(d.get("fanspeed") or 0)
        self.lbl_fan.config(text=str(fan)+" %",fg=RED if fan>90 else ORANGE if fan>70 else GREEN)
        self.lbl_fanrpm.config(text=str(d.get("fanrpm","--"))+" rpm")
        with self._btc_lock:
            _btc_snap=self.btc
        self.lbl_btc.config(text="$"+format(_btc_snap,",.0f") if _btc_snap else "--")
        rssi=(d.get("wifiRSSI") or 0)
        self.lbl_wifi.config(text=str(rssi)+" dBm",fg=GREEN if rssi>-60 else ORANGE if rssi>-75 else RED)
        hostname=d.get("hostname","").upper()
        self.lbl_version.config(text=hostname+"  |  "+d.get("ASICModel","")+"  |  "+d.get("version","")+"  |  ESC to quit")
        self.lbl_status.config(
            text="Updated: "+time.strftime("%H:%M:%S")+"  |  "+d.get("ssid","")+"  |  Blocks: "+str(new_blocks),fg=GOLD)
        try:         self.lbl_refresh_stat.config(text=str(REFRESH)+" s")
        except Exception: pass
        try: getattr(self,"lbl_hr_refresh_stat",None) and self.lbl_hr_refresh_stat.config(text=str(HR_REFRESH)+" s")
        except Exception: pass
        # v3.9.3: cached alert config — no disk I/O every tick
        if _alert_cfg_global_cache is None:
            _alert_cfg_global_cache = load_alert_config()
        _acfg = _alert_cfg_global_cache
        _wh=_acfg.get("discord_webhook","")
        _alm_temp=float(_acfg.get("alert_temp_threshold",85))
        _alm_hash=float(_acfg.get("alert_hash_threshold",0.5))
        _alm_vr=float(_acfg.get("alert_vr_temp_threshold",85))
        if temp>=_alm_temp and not self._alerted_temp:
            send_discord_alert(_wh,"🔥  MINER OVERHEAT",f"ASIC temp **{round(temp,1)}°C** >= {_alm_temp}°C",color=0xff3030)
            self._alerted_temp=True
        elif temp<_alm_temp-5: self._alerted_temp=False
        if vr_temp>=_alm_vr and not self._alerted_vr_temp:
            send_discord_alert(_wh,"🟠  VR OVERHEAT",f"VR temp **{round(vr_temp,1)}°C** >= {_alm_vr}°C",color=0xff6600)
            self._alerted_vr_temp=True
        elif vr_temp<_alm_vr-5: self._alerted_vr_temp=False
        if hr<_alm_hash and hr>0 and not self._alerted_hash:
            send_discord_alert(_wh,"⚠️  LOW HASHRATE",f"Hashrate **{round(hr,3)} TH/s** < {_alm_hash} TH/s",color=0xff8800)
            self._alerted_hash=True
        elif hr>=_alm_hash: self._alerted_hash=False
        if new_blocks>old_blocks and old_blocks>=0 and _acfg.get("alert_on_block",True):
            send_discord_alert(_wh,"⛏️  BLOCK FOUND!",f"Block found! Total: **{new_blocks}**",color=0x00ff88)
        _rej=d.get("sharesRejected",0); _rd=_rej-getattr(self,"_last_rej",_rej)
        self._last_rej=_rej
        if _rd>=5: send_discord_alert(_wh,"❌  REJECTED SPIKE",f"**{_rd}** shares rejected. Total: {_rej}",color=0xff5500)

    def _reboot_miner(self):
        import tkinter.messagebox as mb
        if mb.askyesno("Reboot Miner", "Are you sure you want to reboot the miner?"):
            try:
                import requests as _req
                _req.post(f"http://{MINER_IP}/api/system/restart", timeout=5)
                self.lbl_status.config(text="Reboot command sent.", fg=ORANGE)
            except Exception as e:
                self.lbl_status.config(text="Reboot failed: " + str(e)[:60], fg=RED)

    def _apply_refresh(self, event=None):
        global REFRESH
        try:
            val = float(self.refresh_var.get())
            if val < 0.5:
                val = 0.5
            REFRESH = val
            self.refresh_var.set(str(val))
        except ValueError:
            self.refresh_var.set(str(REFRESH))

    def _apply_hr_refresh(self, event=None):
        global HR_REFRESH
        try:
            val = float(self.hr_refresh_var.get())
            if val < 0.25:
                val = 0.25
            HR_REFRESH = round(val, 2)
            self.hr_refresh_var.set(str(HR_REFRESH))
            # sync left-panel stat label immediately
            try:
                getattr(self,"lbl_hr_refresh_stat",None) and self.lbl_hr_refresh_stat.config(text=str(HR_REFRESH)+" s")
            except Exception:
                pass
            # reset draw timer so graph refreshes at once with the new rate
            self._last_hr_draw = 0
        except ValueError:
            self.hr_refresh_var.set(str(HR_REFRESH))

    def _pulse_bars(self):
        """Gentle wave pulse on bars when idle (no new data for >3s)."""
        import math, time as _time
        now = _time.time()
        idle = (now - getattr(self, '_last_data_time', now)) > 3
        if idle and self.hr_history:
            self._pulse_phase = getattr(self, '_pulse_phase', 0.0) + 0.08
            c = self.bar_canvas
            c.update_idletasks()
            w = c.winfo_width()
            h = c.winfo_height()
            if h < 10:
                h = 220
            c.delete("all")
            points = list(self.hr_history)[-40:]
            n = len(points)
            if n:
                mx = max(points) or 1
                mn = min(points) or 0
                data_range = max(mx - mn, 0.05)
                floor = mn - data_range * 0.1
                ceiling = mx + data_range * 0.1
                sub_w = max(1.0, (w - 72) / max(1, n * 16))
                seg_h = 5; seg_gap = 2; seg_unit = seg_h + seg_gap
                max_segs = max(1, (h - 4) // seg_unit)
                for i, val in enumerate(points):
                    next_val = points[i+1] if i+1 < n else val
                    for sub in range(16):
                        t = sub / 16.0
                        ease = t * t * (3 - 2 * t)
                        v = val + (next_val - val) * ease
                        base = max(0.0, min(1.0, (v - floor) / max(ceiling - floor, 0.001)))
                        wave = math.sin(self._pulse_phase + (i * 16 + sub) * 0.18) * 0.06
                        norm = max(0.05, min(1.0, base ** 0.6 + wave))
                        _si = i * 16 + sub
                        x0  = int(36 + _si * sub_w)
                        x1  = max(x0 + 1, int(36 + (_si + 1) * sub_w))
                        n_segs = max(1, int(norm * max_segs))
                        bar_top = h - 2 - n_segs * seg_unit
                        if bar_top < h - 2:
                            c.create_rectangle(x0, bar_top, x1, h - 2,
                                               fill="#050514", outline="")
                        # bright top pixel
                        c.create_line(x0, bar_top, x1, bar_top,
                                      fill="#c0c0ff", width=2)
        self.root.after(80, self._pulse_bars)



